    return 0;
}

#include <stdio.h>
// #include <stdlib.h>
#include "riscv_nn_convolution.h"

#define INPUT_X 16
#define INPUT_Y 15
#define INPUT_CH 4
#define KERNEL_X 2
#define KERNEL_Y 3
#define OUTPUT_X 14
#define OUTPUT_Y 14
#define CH_MULT 192
#define PAD_X 0
#define PAD_Y 0
#define STRIDE_X 1
#define STRIDE_Y 1
#define INPUT_OFFSET -99
#define FILTER_OFFSET -109
#define OUTPUT_OFFSET 89
#define OUTPUT_ACTIVATION_MIN 0X00000005
#define OUTPUT_ACTIVATION_MAX 0X000000FA
#define OUT_SHIFT -2
#define OUT_MULT (1<<23)
#define SRC1_LEN (INPUT_CH * INPUT_X * INPUT_Y)
#define SRC2_LEN (INPUT_CH * KERNEL_X * KERNEL_Y * CH_MULT)
#define BIAS_LEN (INPUT_CH * CH_MULT)
#define OUT_LEN  (INPUT_CH * OUTPUT_X * OUTPUT_Y * CH_MULT)

uint8_t src1[SRC1_LEN] FUNC_ATTR_ALIGN;
uint8_t src2[SRC2_LEN] FUNC_ATTR_ALIGN;
int32_t bias[BIAS_LEN] FUNC_ATTR_ALIGN;
uint8_t output[OUT_LEN] FUNC_ATTR_ALIGN;
#if !ENA_RANDOM_INPUT
uint8_t golden[OUT_LEN];
#endif

int main (void)
{
    enable_fs_and_vs();
    uint32_t retStatus=NDS_SUCCESS;

#if ENA_RANDOM_INPUT
    uint32_t i;
    for(i=0; i<SRC1_LEN; i++)
    {
        src1[i] = rand();
    }
    for(i=0; i<SRC2_LEN; i++)
    {
        src2[i] = rand();
    }
    for(i=0; i<BIAS_LEN; i++)
    {
        bias[i] = rand();
    }
#else
    FILE *fptr_src1, *fptr_src2, *fptr_bias;
    test_Fopen("8b_in1.bin", "rb", &fptr_src1);
    test_Fopen("8b_in2.bin", "rb", &fptr_src2);
    test_Fopen("32b_in1.bin", "rb", &fptr_bias);
    test_Fread(src1, sizeof(*src1), SRC1_LEN, fptr_src1, "src1");
    test_Fread(src2, sizeof(*src2), SRC2_LEN, fptr_src2, "src2");
    test_Fread(bias, sizeof(*bias), BIAS_LEN, fptr_bias, "bias");
    fclose(fptr_src1);
    fclose(fptr_src2);
    fclose(fptr_bias);
#endif

#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_conv_dw_HWC_u8_u8_u8_asym_bias_any(src1, INPUT_X, INPUT_Y, INPUT_CH, src2, KERNEL_X, KERNEL_Y, CH_MULT, PAD_X, PAD_Y, STRIDE_X, STRIDE_Y, 0, 0, bias, INPUT_OFFSET, FILTER_OFFSET, OUTPUT_OFFSET, output, OUTPUT_X, OUTPUT_Y, OUTPUT_ACTIVATION_MIN, OUTPUT_ACTIVATION_MAX, OUT_SHIFT, OUT_MULT);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if !ENA_RANDOM_INPUT
    FILE *fptr_golden;
    test_Fopen("conv_dw_u8_golden3.bin", "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), OUT_LEN, fptr_golden, "golden");
    uint32_t maxDiff = verify_buffer(output, golden, OUT_LEN, sizeof(*golden));
    if (maxDiff > 1)
    {
        printf("accuracy checking fail\n\n");
        retStatus |= NDS_FAILURE;
    }
    else
    {
        printf("accuracy checking pass\n\n");
        retStatus |= NDS_SUCCESS;
    }
    fclose(fptr_golden);
#endif

    return retStatus;
}
